bd list --parent ct-wisp-wisp-g596 --json 2>/dev/null | python3 -c "
import json, sys
data = json.load(sys.stdin)
# Find each step's blockers (things that block THIS step)
for d in data:
    deps = d.get('dependencies', [])
    # 'blocks' where depends_on_id is this step means something blocks us
    # Actually need to understand the dep model better
    blockers = []
    for dep in deps:
        if dep['type'] == 'blocks' and dep['depends_on_id'] == d['id']:
            blockers.append(dep['issue_id'])
    blocks_others = []
    for dep in deps:
        if dep['type'] == 'blocks' and dep['issue_id'] == d['id']:
            blocks_others.append(dep['depends_on_id'])
    print(f\"{d['id']}: {d['title']}")
    if blockers:
        print(f'  blocked_by: {blockers}')
    if blocks_others:
        print(f'  blocks: {blocks_others}')
    print()
"

bd list --type=agent --desc-contains="role_type: witness" --json 2>/dev/null | python3 -c '
import json, sys, re
data = json.load(sys.stdin)
results = []
for d in data:
    if d.get("status") == "closed":
        continue
    desc = d.get("description", "")
    if re.search(r"(?m)^\s*rig: claude_temp\s*$", desc):
        results.append(d["id"])
for r in results:
    print(r)
'
